values.content:
={{ (() => {
  const lateCount = $json.late_count;
  const name = $json.name;
  const date = $json.date;
  const checkIn = $json.check_in;
  const meetingLink = $json.meeting_link || 'TBD';

  if (lateCount === 1) {
    return `CONTEXT: Employee ${name} arrived late on ${date} at ${checkIn}. Strike 1 this month. TONE: Friendly, supportive. TASK: Write a gentle reminder about 11:00 AM policy.`;
  } else if (lateCount === 2) {
    return `CONTEXT: Employee ${name} has reached strike 2 this month (latest: ${date} at ${checkIn}). TONE: Professional, firm. TASK: Write a formal warning. Mention 3rd strike = mandatory meeting.`;
  } else {
    return `CONTEXT: Employee ${name} has reached STRIKE 3 this month (${date}). Meeting scheduled today 5 PM. Link: ${meetingLink}. TONE: Urgent, authoritative. TASK: Write final warning with meeting details.`;
  }
})() }}
